#include <bits/stdc++.h>
using namespace std;
int n,m,a[10005][105],num,ans=0;
vector<int> v[10005];
const int N=20123;
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            int k;
            cin>>k;
            if(k==1) v[i].push_back(j);
            cin>>a[i][j];
        }
    }
    cin>>num;
    num++;
    for(int i=1;i<=n;i++)
    {
        ans+=a[i][num];
        ans%=N;
        int t=a[i][num]%v[i].size();
        if(t==0) t=v[i].size();
        int k=lower_bound(v[i].begin(),v[i].end(),num)-v[i].begin();
        k%=v[i].size();
        for(int j=1;j<t;j++) k=(k+1)%v[i].size();
        num=v[i][k];
    }
    cout<<ans;
    return 0;
}
